@startuml
skinparam classStyle rectangle
skinparam class {
  BackgroundColor White
  BorderColor Black
  FontColor Black
}

class "A Listenable" {
  void addListener(VoidCallback listener)
  void removeListener(VoidCallback listener)
}

class "A ValueListenable" {
  T get value
}

class "C ChangeNotifier" {
  ObserverList<VoidCallback> _listeners
  bool get hasListeners
  void dispose()
  void notifyListeners()
}

class "C ValueNotifier" {
  T get value
  set value(T newValue)
}

"A Listenable" <|-- "A ValueListenable"
"A Listenable" <|-- "C ChangeNotifier"
"A ValueListenable" <|-- "C ValueNotifier"

"C ValueNotifier" ..> "A ValueListenable"
"C ValueNotifier" ..> "C ChangeNotifier"

@enduml
